from lxml import etree
import io

def process_soap_request(xml_content):
    # Enable DTD validation
    parser = etree.XMLParser(load_dtd=True, no_network=False, recover=True, schema=None)
    
    try:
        # Parse the XML content with DTD validation
        root = etree.fromstring(xml_content, parser)
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {e}")
    
    # Check if it's a SOAP envelope
    soap_namespace = "http://schemas.xmlsoap.org/soap/envelope/"
    if root.tag != f"{{{soap_namespace}}}Envelope":
        raise ValueError("Not a valid SOAP envelope")
    
    # Find the SOAP body
    body = root.find(f".//{{{soap_namespace}}}Body")
    if body is None:
        raise ValueError("SOAP body not found")
    
    # Extract message body content
    message_content = []
    for child in body:
        # Serialize the child element back to string
        message_content.append(etree.tostring(child, encoding='unicode', pretty_print=True))
    
    return message_content

def process_soap_request_with_dtd(xml_content, dtd_content=None):
    # Create parser with DTD support
    parser = etree.XMLParser(load_dtd=True, no_network=False, recover=True)
    
    try:
        # Parse with DTD validation
        root = etree.fromstring(xml_content, parser)
    except etree.XMLSyntaxError as e:
        raise ValueError(f"XML parsing failed: {e}")
    
    # Validate against provided DTD if given
    if dtd_content:
        dtd = etree.DTD(dtd_content)
        if not dtd.validate(root):
            raise ValueError("DTD validation failed")
    
    # Extract SOAP body
    soap_namespace = "http://schemas.xmlsoap.org/soap/envelope/"
    body = root.find(f".//{{{soap_namespace}}}Body")
    if body is None:
        raise ValueError("SOAP body not found")
    
    # Return message content as list of strings
    message_content = []
    for child in body:
        message_content.append(etree.tostring(child, encoding='unicode', pretty_print=True))
    
    return message_content